const listWorkerSkills = `-- name: ListWorkerSkills :many
SELECT
    ws.id, ws.tenant_id, ws.worker_profile_id, ws.skill_id, ws.skill_name_snapshot, ws.proficiency, ws.years_experience, ws.last_used_on, ws.verification_status, ws.certificate_url, ws.certificate_expires_on, ws.assessment_score, ws.assessed_on, ws.endorsed_by, ws.endorsed_at, ws.verified_by, ws.verified_at, ws.notes, ws.metadata, ws.inactive, ws.created_at, ws.created_by, ws.updated_at, ws.updated_by,
    wp.display_name AS worker_display_name,
    wp.worker_code,
    s.code AS skill_code,
    s.name AS skill_name,
    s.skill_type,
    s.source_scope AS skill_source_scope,
    s.certificate_required,
    s.assessment_required,
    sc.name AS category_name,
    sc.code AS category_code
FROM hrms.worker_skills ws
JOIN hrms.worker_profiles wp ON wp.tenant_id = ws.tenant_id AND wp.id = ws.worker_profile_id AND NOT wp.inactive
JOIN hrms.skills s ON s.id = ws.skill_id AND NOT s.inactive
LEFT JOIN hrms.skill_categories sc ON sc.id = s.category_id AND NOT sc.inactive
WHERE ws.tenant_id = $1
  AND ($2::uuid IS NULL OR ws.worker_profile_id = $2::uuid)
  AND ($3::uuid IS NULL OR ws.skill_id = $3::uuid)
  AND ($4::uuid IS NULL OR s.category_id = $4::uuid)
  AND ($5::text IS NULL OR ws.proficiency = $5::text)
  AND ($6::text IS NULL OR ws.verification_status = $6::text)
  AND ($7::date IS NULL OR ws.certificate_expires_on <= $7::date)
  AND (
      $8::text IS NULL
      OR wp.display_name ILIKE '%' || $8::text || '%'
      OR wp.worker_code ILIKE '%' || $8::text || '%'
      OR s.code ILIKE '%' || $8::text || '%'
      OR s.name ILIKE '%' || $8::text || '%'
      OR ws.skill_name_snapshot ILIKE '%' || $8::text || '%'
  )
  AND NOT ws.inactive
ORDER BY
    CASE ws.verification_status
        WHEN 'hr_verified' THEN 1
        WHEN 'manager_endorsed' THEN 2
        WHEN 'self_declared' THEN 3
        WHEN 'expired' THEN 4
        ELSE 5
    END,
    wp.display_name ASC,
    s.name ASC
`

